fn worse_transition(a: Option<Tier>, b: Option<Tier>) -> Option<Tier> {
    match (a, b) {
        (None, None) => None,
        (Some(t), None) | (None, Some(t)) => Some(t),
        (Some(a), Some(b)) => {
            // Tier ordering: Forgotten < Cold < Warm < Hot
            // "Worse" = lower tier
            if a <= b { Some(a) } else { Some(b) }
        }
    }
}
